// 分析關鍵詞和語義標籤的頻率
const articles = $input.all();
const keywordFrequency = {};
const tagFrequency = {};

// 統計關鍵詞頻率
articles.forEach(article => {
  const keywords = article.json.keywords || [];
  keywords.forEach(kw => {
    keywordFrequency[kw] = (keywordFrequency[kw] || 0) + 1;
  });

  const tags = article.json.semantic_tags || [];
  tags.forEach(tag => {
    tagFrequency[tag] = (tagFrequency[tag] || 0) + 1;
  });
});

// 找出高頻關鍵詞
const topKeywords = Object.entries(keywordFrequency)
  .filter(([_, count]) => count >= 3) // 至少出現 3 次
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10) // 取前 10
  .map(([keyword, count]) => ({ keyword, count }));

// 找出高頻標籤
const topTags = Object.entries(tagFrequency)
  .filter(([_, count]) => count >= 3)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([tag, count]) => ({ tag, count }));

return [{
  json: {
    top_keywords: topKeywords,
    top_tags: topTags,
    total_articles: articles.length,
    analysis_date: new Date().toISOString()
  }
}];

const articles = $input.all();
const categories = new Set();

articles.forEach(article => {
  if (article.json.category) {
    categories.add(article.json.category);
  }
});

return [{
  json: {
    existing_categories: Array.from(categories)
  }
}];

