const response = $input.first().json.choices[0].message.content;
const suggestion = JSON.parse(response);

if (!suggestion.should_create_category) {
  return [{
    json: {
      action: 'no_new_category',
      message: '沒有需要建立的新分類',
      timestamp: new Date().toISOString()
    }
  }];
}

// 為每個建議分類生成項目
const items = suggestion.suggested_categories.map(cat => ({
  json: {
    action: 'suggest_new_category',
    category_name: cat.name,
    reason: cat.reason,
    related_keywords: cat.related_keywords,
    difficulty_level: cat.difficulty_level,
    suggested_at: new Date().toISOString(),
    status: 'pending_approval'
  }
}));

return items;

